package tests;import base.BaseTestPlaywright;import com.microsoft.playwright.Page;import org.junit.jupiter.api.Test;import java.nio.file.Paths;import static org.junit.jupiter.api.Assertions.assertTrue;public class HP10RegistroExitosoPlaywrightTest extends BaseTestPlaywright {    @Test    void registroExitosoConTodosLosCamposValidos() {        page.navigate("https://ernest.xo.je/index.php?route=auth/register");        String usuarioUnico =                "jperez" + System.currentTimeMillis();        page.locator("input[name='name']")                .fill("Juan Perez");        page.locator("input[name='username']")                .fill(usuarioUnico);        page.locator("input[name='password']")                .fill("clave123");        page.locator("button[type='submit']")                .click();        page.waitForTimeout(2000);        String contenido = page.content().toLowerCase();        String url = page.url().toLowerCase();        assertTrue(                contenido.contains("login")                        || contenido.contains("iniciar")                        || contenido.contains("registr")                        || contenido.contains("pendiente")                        || url.contains("login"),                "El sistema no registró correctamente al usuario."        );        page.screenshot(                new Page.ScreenshotOptions()                        .setPath(Paths.get(                                "evidencias/HP10-registro-exitoso.png"))                        .setFullPage(true)        );    }}